import java.util.ArrayList;
import java.util.List;

public List<List<Integer>> findFarmland(int[][] land) {
    int m = land.length, n = land[0].length;
    List<List<Integer>> res = new ArrayList<>();

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (land[i][j] == 1) {
                int r = i, c = j;
                while (r < m && land[r][j] == 1) ++r;
                while (c < n && land[i][c] == 1) ++c;
                for (int x = i; x < r; ++x) {
                    for (int y = j; y < c; ++y) {
                        land[x][y] = 0;
                    }
                }
                res.add(List.of(i, j, r - 1, c - 1));
            }
        }
    }

    return res;
}
```


